console.log("TENANT_API:", TENANT_API);
console.log("ASSET_API:", ASSET_API);
console.log("INCIDENT_API:", INCIDENT_API);

import React, { useEffect, useState } from "react";

const TENANT_API = process.env.REACT_APP_TENANT_API;
const ASSET_API = process.env.REACT_APP_ASSET_API;
const INCIDENT_API = process.env.REACT_APP_INCIDENT_API;

// Utility function for safe JSON parsing
async function fetchJSON(url, options = {}) {
  const response = await fetch(url, options);

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Error ${response.status}: ${text}`);
  }

  const contentType = response.headers.get("content-type");
  if (contentType && contentType.includes("application/json")) {
    return response.json();
  } else {
    const text = await response.text();
    throw new Error(`Expected JSON but received: ${text}`);
  }
}

function App() {
  const [tenants, setTenants] = useState([]);
  const [selectedTenant, setSelectedTenant] = useState(
    localStorage.getItem("tenantId") || ""
  );
  const [tenantName, setTenantName] = useState("");
  const [adminEmail, setAdminEmail] = useState("");

  const [assets, setAssets] = useState([]);
  const [incidents, setIncidents] = useState([]);

  const [assetName, setAssetName] = useState("");
  const [assetType, setAssetType] = useState("");

  const [incidentTitle, setIncidentTitle] = useState("");
  const [incidentAssetId, setIncidentAssetId] = useState("");
  const [severity, setSeverity] = useState("Low");

  // Load tenants on startup
  useEffect(() => {
    loadTenants();
  }, []);

  // Load dashboard data when tenant changes
  useEffect(() => {
    if (selectedTenant) {
      localStorage.setItem("tenantId", selectedTenant);
      loadDashboard();
    }
  }, [selectedTenant]);

  const loadTenants = async () => {
    try {
      const data = await fetchJSON(TENANT_API);
      setTenants(data);

      if (!selectedTenant && data.length > 0) {
        setSelectedTenant(data[0].tenantId);
      }
    } catch (error) {
      console.error("Error loading tenants:", error);
    }
  };

  const loadDashboard = async () => {
    try {
      const headers = { "X-Tenant-ID": selectedTenant };

      const assetsData = await fetchJSON(ASSET_API, { headers });
      const incidentsData = await fetchJSON(INCIDENT_API, { headers });

      setAssets(assetsData);
      setIncidents(incidentsData);
    } catch (error) {
      console.error("Error loading dashboard:", error);
    }
  };

  const createTenant = async (e) => {
    e.preventDefault();
    try {
      await fetchJSON(TENANT_API, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: tenantName, adminEmail }),
      });
      setTenantName("");
      setAdminEmail("");
      loadTenants();
    } catch (error) {
      console.error("Error creating tenant:", error);
    }
  };

  const createAsset = async (e) => {
    e.preventDefault();
    try {
      await fetchJSON(ASSET_API, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Tenant-ID": selectedTenant,
        },
        body: JSON.stringify({ name: assetName, type: assetType }),
      });
      setAssetName("");
      setAssetType("");
      loadDashboard();
    } catch (error) {
      console.error("Error creating asset:", error);
    }
  };

  const createIncident = async (e) => {
    e.preventDefault();
    try {
      await fetchJSON(INCIDENT_API, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Tenant-ID": selectedTenant,
        },
        body: JSON.stringify({
          title: incidentTitle,
          assetId: incidentAssetId,
          severity,
        }),
      });
      setIncidentTitle("");
      setIncidentAssetId("");
      setSeverity("Low");
      loadDashboard();
    } catch (error) {
      console.error("Error creating incident:", error);
    }
  };

  return (
    <div>
      <header className="header">
        <h2>🏢 Multi-Tenant ITOM Dashboard</h2>
        <div>
          <label>Select Tenant: </label>
          <select
            value={selectedTenant}
            onChange={(e) => setSelectedTenant(e.target.value)}
          >
            {tenants.map((tenant) => (
              <option key={tenant.tenantId} value={tenant.tenantId}>
                {tenant.name}
              </option>
            ))}
          </select>
        </div>
      </header>

      <div className="container">
        {/* Tenant Onboarding */}
        <div className="form-card">
          <h3>Onboard New Tenant</h3>
          <form onSubmit={createTenant}>
            <input
              type="text"
              placeholder="Tenant Name"
              value={tenantName}
              onChange={(e) => setTenantName(e.target.value)}
              required
            />
            <input
              type="email"
              placeholder="Admin Email"
              value={adminEmail}
              onChange={(e) => setAdminEmail(e.target.value)}
              required
            />
            <button type="submit">Create Tenant</button>
          </form>
        </div>

        {/* KPI Cards */}
        <div className="cards">
          <div className="card">
            <h3>Total Assets</h3>
            <p className="count">{assets.length}</p>
          </div>
          <div className="card">
            <h3>Total Incidents</h3>
            <p className="count">{incidents.length}</p>
          </div>
        </div>

        {/* Add Asset */}
        <div className="form-card">
          <h3>Add Asset</h3>
          <form onSubmit={createAsset}>
            <input
              type="text"
              placeholder="Asset Name"
              value={assetName}
              onChange={(e) => setAssetName(e.target.value)}
              required
            />
            <input
              type="text"
              placeholder="Asset Type"
              value={assetType}
              onChange={(e) => setAssetType(e.target.value)}
              required
            />
            <button type="submit">Create Asset</button>
          </form>
        </div>

        {/* Report Incident */}
        <div className="form-card">
          <h3>Report Incident</h3>
          <form onSubmit={createIncident}>
            <input
              type="text"
              placeholder="Incident Title"
              value={incidentTitle}
              onChange={(e) => setIncidentTitle(e.target.value)}
              required
            />
            <select
              value={incidentAssetId}
              onChange={(e) => setIncidentAssetId(e.target.value)}
              required
            >
              <option value="">Select Related Asset</option>
              {assets.map((asset) => (
                <option key={asset.id} value={asset.id}>
                  {asset.name}
                </option>
              ))}
            </select>
            <select
              value={severity}
              onChange={(e) => setSeverity(e.target.value)}
            >
              <option value="Low">Low</option>
              <option value="Medium">Medium</option>
              <option value="High">High</option>
            </select>
            <button type="submit">Create Incident</button>
          </form>
        </div>

        {/* Recent Lists */}
        <div className="lists">
          <div className="list">
            <h3>Recent Assets</h3>
            <ul>
              {assets.slice(-5).reverse().map((asset) => (
                <li key={asset.id}>
                  {asset.name} ({asset.type})
                </li>
              ))}
            </ul>
          </div>
          <div className="list">
            <h3>Recent Incidents</h3>
            <ul>
              {incidents.slice(-5).reverse().map((incident) => (
                <li key={incident.id}>
                  {incident.title} - {incident.severity}
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
